require 'sketchup.rb'

def generate_lumion_ready_model
  model = Sketchup.active_model
  entities = model.entities
  
  # Clear existing entities in the model to start fresh
  entities.clear!
  
  # ----------------------------------------------------
  # STEP 1: SET UNITS AND OPTIONS
  # ----------------------------------------------------
  model.options['UnitsOptions']['LengthUnit'] = 2 # 2 = Millimeters
  model.options['UnitsOptions']['LengthFormat'] = 0 # Decimal
  model.options['UnitsOptions']['LengthPrecision'] = 0
  
  # Disable scene transitions for fast execution
  model.options['PageOptions']['ShowTransition'] = false
  model.options['PageOptions']['TransitionTime'] = 0.0
  
  # ----------------------------------------------------
  # STEP 2: CREATE TAGS (LAYERS)
  # ----------------------------------------------------
  layers = model.layers
  tags = [
    "RV_Container_Modules",
    "RV_Walls",
    "RV_Glass",
    "RV_Doors_Windows",
    "RV_Roof",
    "RV_Deck",
    "RV_Courtyard",
    "RV_Landscape_Base",
    "RV_Landscape_Foliage",
    "RV_Furniture",
    "RV_Utilities",
    "RV_Lighting",
    "RV_Annotations"
  ]
  tags.each { |t| layers.add(t) }
  
  # ----------------------------------------------------
  # STEP 3: CREATE LUMION-SPECIFIC MATERIALS (RV_ Prefix)
  # ----------------------------------------------------
  materials = model.materials
  
  def add_material(materials, name, r, g, b, alpha = 1.0)
    mat = materials[name] || materials.add(name)
    mat.color = Sketchup::Color.new(r, g, b)
    mat.alpha = alpha
    mat
  end
  
  m_charcoal_metal = add_material(materials, "RV_Charcoal_Metal", 38, 43, 49)          # Container frames, posts, downpipes
  m_cladding       = add_material(materials, "RV_Teak_Timber_Cladding", 195, 163, 115)   # Fine wall slats, privacy screens
  m_laterite       = add_material(materials, "RV_Laterite_Stone", 156, 73, 57)        # Raised plinth bases, piers, seating, steps
  m_glass          = add_material(materials, "RV_Glass_Dark_Reflective", 100, 149, 162, 0.40) # Widescreen windows, corridor glass
  m_deck           = add_material(materials, "RV_Deck_Timber", 175, 115, 60)            # Outdoor timber veranda and decks
  m_roof           = add_material(materials, "RV_Roof_Matte_Black", 46, 48, 51)         # Standing seam roofing metal
  m_gravel         = add_material(materials, "RV_Path_Gravel", 204, 197, 185)           # Gravel driveway, parking court, base drains
  m_grass          = add_material(materials, "RV_Terrain_Grass", 48, 87, 56)            # Standard site lawn terracing
  m_water          = add_material(materials, "RV_Water_PlungePool", 62, 163, 179, 0.55)  # Plunge pool water, courtyard channel
  m_solar          = add_material(materials, "RV_Solar_Panel", 16, 25, 45)              # Monocrystalline PV cells
  m_floor_wood     = add_material(materials, "RV_Interior_Warm_Floor", 168, 122, 82)    # Sofa frames, dining tables, beds, interior floors
  m_shrubs         = add_material(materials, "RV_Landscape_Shrubs", 26, 54, 34)         # Jungle forest boundary, bamboo stalks
  m_utility        = add_material(materials, "RV_Service_Utility", 24, 24, 24)          # Bio-Digester boxes, rainwater cisterns
  m_pebbles        = add_material(materials, "RV_Pebble_Swale", 150, 140, 130)           # Swale river rocks
  m_emissive       = add_material(materials, "RV_Emissive_Light", 255, 204, 102, 0.90)  # Path light glowing fixtures
  m_canvas         = add_material(materials, "RV_Furniture_Canvas", 232, 226, 214)      # Sand canvas fabric cushions
  
  # Helper to draw a box with front and back material assigned
  def draw_box(entities, x1, y1, z1, x2, y2, z2, material = nil, tag_name = nil)
    group = entities.add_group
    face = group.entities.add_face([x1, y1, z1], [x2, y1, z1], [x2, y2, z1], [x1, y2, z1])
    h = (z2 - z1).to_f
    face.pushpull(h) if h.abs > 0.01
    
    if material
      group.entities.each do |e|
        if e.is_a?(Sketchup::Face)
          e.material = material
          e.back_material = material
        end
      end
      group.material = material
    end
    
    if tag_name
      tag = Sketchup.active_model.layers[tag_name]
      group.layer = tag if tag
    end
    
    group
  end
  
  # Helper to draw a cylinder with front and back material assigned
  def draw_cylinder(entities, x, y, z_bottom, z_top, r, material = nil, tag_name = nil)
    group = entities.add_group
    ge = group.entities
    circle = ge.add_circle([x, y, z_bottom], [0, 0, 1], r, 16)
    face = ge.add_face(circle)
    h = (z_top - z_bottom).to_f
    face.pushpull(h) if h.abs > 0.01
    
    if material
      group.entities.each do |e|
        if e.is_a?(Sketchup::Face)
          e.material = material
          e.back_material = material
        end
      end
      group.material = material
    end
    
    if tag_name
      tag = Sketchup.active_model.layers[tag_name]
      group.layer = tag if tag
    end
    
    group
  end
  
  # Helper to draw vertical privacy screens
  def draw_privacy_screen(entities, x1, y1, x2, y2, z_bottom, z_top, slat_w, slat_d, spacing, material)
    dx = x2 - x1
    dy = y2 - y1
    length = Math.sqrt(dx*dx + dy*dy)
    return if length == 0
    
    num_slats = (length / spacing).floor
    ux = dx / length
    uy = dy / length
    
    num_slats.times do |i|
      sx = x1 + i * spacing * ux
      sy = y1 + i * spacing * uy
      draw_box(entities, sx - slat_w/2.0, sy - slat_d/2.0, z_bottom, sx + slat_w/2.0, sy + slat_d/2.0, z_top, material, "RV_Walls")
    end
  end
  
  # Helper to draw glass railings
  def draw_glass_railing(entities, x1, y1, x2, y2, z, material_post, material_glass)
    dx = x2 - x1
    dy = y2 - y1
    length = Math.sqrt(dx*dx + dy*dy)
    return if length == 0
    
    ux = dx / length
    uy = dy / length
    
    post_spacing = 1500.0
    num_posts = (length / post_spacing).floor + 1
    
    num_posts.times do |i|
      px = x1 + i * post_spacing * ux
      py = y1 + i * post_spacing * uy
      draw_box(entities, px - 20, py - 20, z, px + 20, py + 20, z + 1000, material_post, "RV_Deck")
      
      if i < num_posts - 1
        next_px = x1 + (i + 1) * post_spacing * ux
        next_py = y1 + (i + 1) * post_spacing * uy
        
        # Perpendicular vector to create thickness
        vx = -uy
        vy = ux
        t = 6.0 # half thickness (12mm total)
        
        # Draw a solid glass box
        group = entities.add_group
        ge = group.entities
        
        p1 = [px + 20*ux - t*vx, py + 20*uy - t*vy, z + 50]
        p2 = [next_px - 20*ux - t*vx, next_py - 20*uy - t*vy, z + 50]
        p3 = [next_px - 20*ux + t*vx, next_py - 20*uy + t*vy, z + 50]
        p4 = [px + 20*ux + t*vx, py + 20*uy + t*vy, z + 50]
        
        face = ge.add_face(p1, p2, p3, p4)
        face.pushpull(900) if face
        
        if material_glass
          ge.each do |e|
            if e.is_a?(Sketchup::Face)
              e.material = material_glass
              e.back_material = material_glass
            end
          end
          group.material = material_glass
        end
        
        tag = Sketchup.active_model.layers["RV_Glass"]
        group.layer = tag if tag
      end
    end
  end
  
  # Helper to draw stylized coconut palm trees (multi-height organic trunks)
  def draw_coconut_palm(entities, x, y, h_total, material_trunk, material_frond)
    palm_group = entities.add_group
    palm_group.name = "Coconut Palm"
    pe = palm_group.entities
    
    curr_x = x
    curr_y = y
    h = 0
    segs = 12
    seg_h = h_total / segs.to_f
    segs.times do |i|
      next_x = curr_x + i * 25 * Math.sin(i * 0.5)
      next_y = curr_y + i * 35 * Math.cos(i * 0.5)
      draw_box(pe, curr_x - 120, curr_y - 120, h, next_x + 120, next_y + 120, h + seg_h, material_trunk, "RV_Landscape_Foliage")
      curr_x = next_x
      curr_y = next_y
      h += seg_h
    end
    
    num_fronds = 14
    num_fronds.times do |j|
      angle = j * 2.0 * Math::PI / num_fronds
      fx = curr_x + Math.cos(angle) * 2700
      fy = curr_y + Math.sin(angle) * 2700
      
      vx = -Math.sin(angle)
      vy = Math.cos(angle)
      w = 140.0
      
      frond_group = pe.add_group
      fe = frond_group.entities
      
      p1 = [curr_x - w*vx, curr_y - w*vy, h - 500]
      p2 = [fx - w*vx, fy - w*vy, h - 100]
      p3 = [fx + w*vx, fy + w*vy, h - 100]
      p4 = [curr_x + w*vx, curr_y + w*vy, h - 500]
      
      face = fe.add_face(p1, p2, p3, p4)
      face.pushpull(60) if face
      
      if material_frond
        fe.each do |e|
          if e.is_a?(Sketchup::Face)
            e.material = material_frond
            e.back_material = material_frond
          end
        end
        frond_group.material = material_frond
      end
      
      tag = Sketchup.active_model.layers["RV_Landscape_Foliage"]
      frond_group.layer = tag if tag
    end
    
    tag = Sketchup.active_model.layers["RV_Landscape_Foliage"]
    palm_group.layer = tag if tag
  end
  
  # Helper to draw broadleaf jungle trees
  def draw_jungle_tree(entities, x, y, h_total, material_trunk, material_canopy)
    t_group = entities.add_group
