    te = t_group.entities
    
    # Trunk cylinder
    draw_cylinder(te, x, y, 0, h_total * 0.6, 250, material_trunk, "RV_Landscape_Foliage")
    
    # Canopy blocks
    draw_box(te, x - 1800, y - 1800, h_total * 0.5, x + 1800, y + 1800, h_total * 0.75, material_canopy, "RV_Landscape_Foliage")
    draw_box(te, x - 2200, y - 2200, h_total * 0.65, x + 2200, y + 2200, h_total * 0.9, material_canopy, "RV_Landscape_Foliage")
    draw_box(te, x - 1500, y - 1500, h_total * 0.85, x + 1500, y + 1500, h_total * 1.05, material_canopy, "RV_Landscape_Foliage")
    
    tag = Sketchup.active_model.layers["RV_Landscape_Foliage"]
    t_group.layer = tag if tag
  end
  
