  # Helper to draw a frame and glass for doors/windows
  def draw_opening_frame(entities, x1, y1, x2, y2, z_bottom, z_top, thickness, type)
    frame_thick = 40
    x_min, x_max = [x1, x2].minmax
    y_min, y_max = [y1, y2].minmax
    
    frame_group = entities.add_group
    frame_group.name = type == :door ? "Door Frame" : "Window Frame"
    
    model = Sketchup.active_model
    bronze_mat = model.materials["RV_Charcoal_Metal"]
    glass_mat = model.materials["RV_Glass_Dark_Reflective"]
    fe = frame_group.entities
    
    if y1 == y2
      y = y1
      draw_box(fe, x_min, y - frame_thick/2.0, z_bottom, x_max, y + frame_thick/2.0, z_bottom + frame_thick, bronze_mat, "RV_Doors_Windows")
      draw_box(fe, x_min, y - frame_thick/2.0, z_top - frame_thick, x_max, y + frame_thick/2.0, z_top, bronze_mat, "RV_Doors_Windows")
      draw_box(fe, x_min, y - frame_thick/2.0, z_bottom + frame_thick, x_min + frame_thick, y + frame_thick/2.0, z_top - frame_thick, bronze_mat, "RV_Doors_Windows")
      draw_box(fe, x_max - frame_thick, y - frame_thick/2.0, z_bottom + frame_thick, x_max, y + frame_thick/2.0, z_top - frame_thick, bronze_mat, "RV_Doors_Windows")
      
      if type == :window
        draw_box(fe, x_min + frame_thick, y - 5, z_bottom + frame_thick, x_max - frame_thick, y + 5, z_top - frame_thick, glass_mat, "RV_Glass")
      else
        mid_x = (x_min + x_max)/2.0
        draw_box(fe, x_min + frame_thick, y - 10, z_bottom + frame_thick, mid_x, y + 10, z_top - frame_thick, glass_mat, "RV_Glass")
        draw_box(fe, mid_x, y - 20, z_bottom + frame_thick, x_max - frame_thick, y, z_top - frame_thick, glass_mat, "RV_Glass")
        draw_box(fe, mid_x - 20, y - 25, z_bottom + frame_thick, mid_x + 20, y + 25, z_top - frame_thick, bronze_mat, "RV_Doors_Windows")
      end
    else
      x = x1
      draw_box(fe, x - frame_thick/2.0, y_min, z_bottom, x + frame_thick/2.0, y_max, z_bottom + frame_thick, bronze_mat, "RV_Doors_Windows")
      draw_box(fe, x - frame_thick/2.0, y_min, z_top - frame_thick, x + frame_thick/2.0, y_max, z_top, bronze_mat, "RV_Doors_Windows")
      draw_box(fe, x - frame_thick/2.0, y_min, z_bottom + frame_thick, x + frame_thick/2.0, y_min + frame_thick, z_top - frame_thick, bronze_mat, "RV_Doors_Windows")
      draw_box(fe, x - frame_thick/2.0, y_max - frame_thick, z_bottom + frame_thick, x + frame_thick/2.0, y_max, z_top - frame_thick, bronze_mat, "RV_Doors_Windows")
      
      if type == :window
        draw_box(fe, x - 5, y_min + frame_thick, z_bottom + frame_thick, x + 5, y_max - frame_thick, z_top - frame_thick, glass_mat, "RV_Glass")
      else
        mid_y = (y_min + y_max)/2.0
        draw_box(fe, x - 10, y_min + frame_thick, z_bottom + frame_thick, x + 10, mid_y, z_top - frame_thick, glass_mat, "RV_Glass")
        draw_box(fe, x - 20, mid_y, z_bottom + frame_thick, x, y_max - frame_thick, z_top - frame_thick, glass_mat, "RV_Glass")
        draw_box(fe, x - 25, mid_y - 20, z_bottom + frame_thick, x + 25, mid_y + 20, z_top - frame_thick, bronze_mat, "RV_Doors_Windows")
      end
    end
    
    tag = model.layers["RV_Doors_Windows"]
    frame_group.layer = tag if tag
    frame_group
  end
  
  # Wall drawer with openings and detailed fine timber cladding overlay strips
  def draw_wall_with_openings_and_cladding(entities, x1, y1, x2, y2, z_bottom, z_top, thickness, material_ext, material_int, openings = [])
    if y1 == y2
      y = y1
      x_min, x_max = [x1, x2].minmax
      current_x = x_min
      
      sorted_openings = openings.sort_by { |o| o[:start] }
      sorted_openings.each do |op|
        op_start = x_min + op[:start]
        op_end = op_start + op[:width]
        
        if op_start > current_x
          draw_box(entities, current_x, y - thickness/2.0, z_bottom, op_start, y + thickness/2.0, z_top, material_ext, "RV_Walls")
          slat_spacing = 150.0
          slat_cnt = ((op_start - current_x) / slat_spacing).floor
          slat_cnt.times do |k|
            slat_x = current_x + k * slat_spacing
            draw_box(entities, slat_x - 20, y - thickness/2.0 - 10, z_bottom, slat_x + 20, y - thickness/2.0, z_top, Sketchup.active_model.materials["RV_Teak_Timber_Cladding"], "RV_Walls")
          end
        end
        
        if op[:type] == :window && op[:sill] > 0
          draw_box(entities, op_start, y - thickness/2.0, z_bottom, op_end, y + thickness/2.0, z_bottom + op[:sill], material_ext, "RV_Walls")
        end
        
        op_top = z_bottom + op[:sill] + op[:height]
        if op_top < z_top
          draw_box(entities, op_start, y - thickness/2.0, op_top, op_end, y + thickness/2.0, z_top, material_ext, "RV_Walls")
        end
        
        draw_opening_frame(entities, op_start, y, op_end, y, z_bottom + op[:sill], z_bottom + op[:sill] + op[:height], thickness, op[:type])
        current_x = op_end
      end
      
      if x_max > current_x
        draw_box(entities, current_x, y - thickness/2.0, z_bottom, x_max, y + thickness/2.0, z_top, material_ext, "RV_Walls")
        slat_spacing = 150.0
        slat_cnt = ((x_max - current_x) / slat_spacing).floor
        slat_cnt.times do |k|
          slat_x = current_x + k * slat_spacing
          draw_box(entities, slat_x - 20, y - thickness/2.0 - 10, z_bottom, slat_x + 20, y - thickness/2.0, z_top, Sketchup.active_model.materials["RV_Teak_Timber_Cladding"], "RV_Walls")
        end
      end
      
    elsif x1 == x2
      x = x1
      y_min, y_max = [y1, y2].minmax
      current_y = y_min
      
      sorted_openings = openings.sort_by { |o| o[:start] }
      sorted_openings.each do |op|
        op_start = y_min + op[:start]
        op_end = op_start + op[:width]
        
        if op_start > current_y
          draw_box(entities, x - thickness/2.0, current_y, z_bottom, x + thickness/2.0, op_start, z_top, material_ext, "RV_Walls")
          slat_spacing = 150.0
          slat_cnt = ((op_start - current_y) / slat_spacing).floor
          slat_cnt.times do |k|
            slat_y = current_y + k * slat_spacing
            draw_box(entities, x - thickness/2.0 - 10, slat_y - 20, z_bottom, x - thickness/2.0, slat_y + 20, z_top, Sketchup.active_model.materials["RV_Teak_Timber_Cladding"], "RV_Walls")
          end
        end
        
        if op[:type] == :window && op[:sill] > 0
          draw_box(entities, x - thickness/2.0, op_start, z_bottom, x + thickness/2.0, op_end, z_bottom + op[:sill], material_ext, "RV_Walls")
        end
        
        op_top = z_bottom + op[:sill] + op[:height]
        if op_top < z_top
          draw_box(entities, x - thickness/2.0, op_start, op_top, x + thickness/2.0, op_end, z_top, material_ext, "RV_Walls")
        end
        
        draw_opening_frame(entities, x, op_start, x, op_end, z_bottom + op[:sill], z_bottom + op[:sill] + op[:height], thickness, op[:type])
        current_y = op_end
      end
      
      if y_max > current_y
        draw_box(entities, x - thickness/2.0, current_y, z_bottom, x + thickness/2.0, y_max, z_top, material_ext, "RV_Walls")
        slat_spacing = 150.0
        slat_cnt = ((y_max - current_y) / slat_spacing).floor
        slat_cnt.times do |k|
          slat_y = current_y + k * slat_spacing
          draw_box(entities, x - thickness/2.0 - 10, slat_y - 20, z_bottom, x - thickness/2.0, slat_y + 20, z_top, Sketchup.active_model.materials["RV_Teak_Timber_Cladding"], "RV_Walls")
        end
      end
    end
  end
  
  # ----------------------------------------------------
  # STEP 4: DRAW MULTI-LEVEL SITE CONTEXT
  # ----------------------------------------------------
  plot_w = 64000
  x_min = 6100 - plot_w/2.0
  x_max = 6100 + plot_w/2.0
  y_min = 8540 - plot_w/2.0
  y_max = 8540 + plot_w/2.0
  
  # Grass Terrain Terraces
  draw_box(entities, x_min, y_min, -300, x_max, -4000, -200, m_grass, "RV_Landscape_Base") # Low
  draw_box(entities, x_min, -4000, -200, x_max, 17080, 0, m_grass, "RV_Landscape_Base") # Mid
  draw_box(entities, x_min, 17080, 0, x_max, y_max, 250, m_grass, "RV_Landscape_Base") # High
  
  # Laterite Retaining Walls
  draw_box(entities, x_min, -4150, -200, x_max, -3850, 50, m_laterite, "RV_Landscape_Base")
  draw_box(entities, x_min, 16930, 0, x_max, 17230, 300, m_laterite, "RV_Landscape_Base")
  
  # Organic Curved Step Pathway
  15.times do |i|
    t = i / 14.0
