  draw_box(entities, 2500, 10200, 550, 3000, 11200, 1300, m_utility, "RV_Utilities")
  draw_box(entities, 4200, 10400, 550, 4700, 10900, 900, m_utility, "RV_Utilities")
  draw_box(entities, 3500, 12000, 550, 3520, 13500, 2400, m_glass, "RV_Glass")
  
  # ----------------------------------------------------
  # STEP 14: HIGH-FIDELITY TROPICAL VEGETATION
  # ----------------------------------------------------
  # Left Boundary Forest Line
  draw_coconut_palm(entities, -18000, -15000, 13000, m_deck, m_shrubs)
  draw_coconut_palm(entities, -22000, -5000, 11000, m_deck, m_shrubs)
  draw_jungle_tree(entities, -21000, 2000, 14000, m_deck, m_shrubs)
  draw_coconut_palm(entities, -20000, 9000, 12000, m_deck, m_shrubs)
  draw_jungle_tree(entities, -23000, 17000, 15000, m_deck, m_shrubs)
  draw_coconut_palm(entities, -18000, 25000, 10000, m_deck, m_shrubs)
  
  # Right Boundary Forest Line
  draw_coconut_palm(entities, 28000, -15000, 11500, m_deck, m_shrubs)
  draw_jungle_tree(entities, 29000, -8000, 13500, m_deck, m_shrubs)
  draw_coconut_palm(entities, 32000, -2000, 13000, m_deck, m_shrubs)
  draw_jungle_tree(entities, 30000, 5000, 15000, m_deck, m_shrubs)
  draw_coconut_palm(entities, 34000, 15000, 12000, m_deck, m_shrubs)
  draw_jungle_tree(entities, 28000, 23000, 14000, m_deck, m_shrubs)
  
  # North perimeter forest buffer
  draw_jungle_tree(entities, -25000, 31000, 16000, m_deck, m_shrubs)
  draw_jungle_tree(entities, -15000, 32000, 15000, m_deck, m_shrubs)
  draw_jungle_tree(entities, -5000, 33000, 14000, m_deck, m_shrubs)
  draw_jungle_tree(entities, 5000, 34000, 15500, m_deck, m_shrubs)
  draw_jungle_tree(entities, 15000, 32000, 16000, m_deck, m_shrubs)
  draw_jungle_tree(entities, 25000, 31000, 15000, m_deck, m_shrubs)
  
  # Bamboo clusters at corners
  draw_bamboo_cluster(entities, -18000, -22000, 8, m_grass)
  draw_bamboo_cluster(entities, 22000, -22000, 8, m_grass)
  draw_bamboo_cluster(entities, -10000, 28000, 6, m_grass)
  draw_bamboo_cluster(entities, 10000, 28000, 6, m_grass)
  
  # Rock clusters
  draw_rock_cluster(entities, 7500, -18000, 5, m_laterite)
  draw_rock_cluster(entities, -12000, 22000, 4, m_laterite)
  
  # ----------------------------------------------------
  # STEP 15: PURGE UNUSED MATERIALS/DEFINITIONS FOR LUMION
  # ----------------------------------------------------
  model.definitions.purge_unused
  model.materials.purge_unused
  
  # ----------------------------------------------------
  # STEP 16: CREATE SCENES FOR LUMION CAMERA REFERENCE
  # ----------------------------------------------------
  pages = model.pages
  while pages.count > 0
    pages.erase(pages[0])
  end
  
  def setup_scene(name, eye_coords, target_coords, perspective = true, height = nil)
    model = Sketchup.active_model
    view = model.active_view
    camera = view.camera
    
    camera.perspective = perspective
    if height && !perspective
      camera.height = height
    end
    
    eye = Geom::Point3d.new(eye_coords[0], eye_coords[1], eye_coords[2])
    target = Geom::Point3d.new(target_coords[0], target_coords[1], target_coords[2])
    
    dx = (target.x - eye.x).abs
    dy = (target.y - eye.y).abs
    if dx < 1 && dy < 1
      up = Geom::Vector3d.new(0, 1, 0)
    else
      up = Geom::Vector3d.new(0, 0, 1)
    end
    
    camera.set(eye, target, up)
    
    page = model.pages.add(name)
    page.update(1) # camera flag
    page
  end
  
  # Setup the exact 8 camera views requested for the Lumion rendering workflow
  setup_scene("01 Website Hero Wide View", [48000, -25000, 18000], [6100, 8540, 1200], true)
  setup_scene("02 Front Arrival View", [6100, -12000, 2000], [6100, 2000, 1800], true)
  setup_scene("03 Aerial Estate View", [35000, -18000, 20000], [6100, 8540, 1500], true)
  setup_scene("04 Courtyard Lifestyle View", [6100, 5000, 1600], [6100, 12000, 2200], true)
  setup_scene("05 Deck + Forest View", [6100, -9000, 1500], [6100, 2000, 2200], true)
  setup_scene("06 Roof Solar + Eco Systems View", [-10000, 22000, 15000], [6100, 8540, 3000], true)
  setup_scene("07 Night Luxury View", [22000, -10000, 6000], [6100, 8540, 1500], true)
  setup_scene("08 Brochure Cover View", [6100, -14000, 3000], [6100, 1000, 1500], true)
  
  # ----------------------------------------------------
  # STEP 17: EXPORT COMPLETED LUMION-READY PACKAGE
  # ----------------------------------------------------
  output_dir = "C:/Users/INTEL/Desktop/GOA/WEBSITE/Model/Layout/Lumion_Export_Package"
  Dir.mkdir(output_dir) unless Dir.exist?(output_dir)
  
  lumion_skp_path = File.join(output_dir, "Reserva_Varde_2BHK_Lumion_Ready.skp")
  status_skp = model.save(lumion_skp_path)
  puts "Lumion-Ready Model SKP saved successfully: #{status_skp} at #{lumion_skp_path}"
  
  lumion_dae_path = File.join(output_dir, "Reserva_Varde_2BHK_Lumion_Export.dae")
  status_dae = model.export(lumion_dae_path)
  puts "Lumion Collada DAE exported successfully: #{status_dae} at #{lumion_dae_path}"
  
  # Write a local ruby error check confirmation
  File.write(File.join(output_dir, "ruby_compile_success.log"), "Success! Lumion-Ready SketchUp and Collada DAE files generated cleanly.")
end

